:deep(.el-divider) {
  margin: 5px auto;
}

.content-menu {
  position: fixed;
  font-size: 12px;
  background: #fff;
  box-shadow: 0 2px 8px 2px rgba(68, 73, 77, 0.16);
  z-index: 999999;
  transform-origin: 0 0;
  font-weight: 600;
  padding: 4px 0;
  overflow: auto;
  max-height: 80%;
  min-width: 180px;

  .menu-item {
    color: #333;
    display: flex;
    -webkit-box-align: center;
    align-items: center;
    flex-direction: row;
    vertical-align: middle;
    cursor: pointer;
    line-height: 35px;
    min-width: 140px;
    transition: all 0.2s ease 0s;
    padding: 5px 14px;
    border-left: 2px solid transparent;

    .button {
      width: 100%;
      justify-content: flex-start;
    }

    .el-button--text, i {
      color: var(--star-horse-style);
    }

    svg {
      margin-right: 5px;
    }

    &.divider {
      padding: 0 14px;

      .el-divider {
        margin: 0;
      }
    }

    &.button {
      &:hover {
        background-color: #6b778c;

        &.menu-item i {
          color: var(--star-horse-style);
        }
      }

      &.active {
        background-color: #6b778c;


        &.menu-item i {
          color: #fff;
        }
      }
    }
  }
}

